from dataclasses import dataclass
from enum import Enum


class ActionClass(Enum):
    READ_ONLY = 1         # no external state changed; always safe to retry
    REVERSIBLE_WRITE = 2  # state changed but can be undone (git, backup)
    HARD_TO_REVERSE = 3   # possible to undo but expensive
    IRREVERSIBLE = 4      # permanent; cannot be undone


@dataclass
class ActionMeta:
    """Metadata about one tool's action class, for use in dispatch and logging."""
    name: str
    action_class: ActionClass
    description: str

    @property
    def requires_confirmation(self) -> bool:
        return self.action_class.value >= 3

    @property
    def safe_to_retry(self) -> bool:
        return self.action_class == ActionClass.READ_ONLY


# Classify every tool in the inventory
ACTION_METADATA: dict[str, ActionMeta] = {
    "read_file": ActionMeta(
        "read_file", ActionClass.READ_ONLY,
        "Reads file contents. No state changed.",
    ),
    "search_code": ActionMeta(
        "search_code", ActionClass.READ_ONLY,
        "Searches codebase with ripgrep.",
    ),
    "write_file": ActionMeta(
        "write_file", ActionClass.REVERSIBLE_WRITE,
        "Writes a file. Reversible via git checkout.",
    ),
    "git_commit": ActionMeta(
        "git_commit", ActionClass.REVERSIBLE_WRITE,
        "Commits staged changes. Reversible with git reset.",
    ),
    "git_push": ActionMeta(
        "git_push", ActionClass.HARD_TO_REVERSE,
        "Pushes to remote. Requires force-push to undo.",
    ),
    "delete_file": ActionMeta(
        "delete_file", ActionClass.IRREVERSIBLE,
        "Permanently deletes a file.",
    ),
    "send_email": ActionMeta(
        "send_email", ActionClass.IRREVERSIBLE,
        "Sends an email. Cannot be recalled.",
    ),
}

import pytest


class TestActionMeta:
    def test_read_only_does_not_require_confirmation(self):
        meta = ActionMeta("read_file", ActionClass.READ_ONLY, "")
        assert meta.requires_confirmation is False

    def test_hard_to_reverse_requires_confirmation(self):
        meta = ActionMeta("git_push", ActionClass.HARD_TO_REVERSE, "")
        assert meta.requires_confirmation is True

    def test_irreversible_requires_confirmation(self):
        meta = ActionMeta("delete_file", ActionClass.IRREVERSIBLE, "")
        assert meta.requires_confirmation is True

    def test_read_only_safe_to_retry(self):
        meta = ActionMeta("read_file", ActionClass.READ_ONLY, "")
        assert meta.safe_to_retry is True

    def test_reversible_write_not_safe_to_retry(self):
        meta = ActionMeta("write_file", ActionClass.REVERSIBLE_WRITE, "")
        assert meta.safe_to_retry is False


class TestDispatchWithConfirmation:
    def test_denied_action_returns_error_string(self):
        def deny_all(name, inp):
            return False

        result = dispatch_with_confirmation(
            name="git_push",
            input={"branch": "main"},
            auto_confirm_classes={ActionClass.READ_ONLY},
            confirm_fn=deny_all,
        )
        assert "DENIED" in result
        assert "git_push" in result
